// M02 §6 Schritt 2 — assert_status
// Akzeptierte Eingangs-Status: 'extracted', 'categorized'.
const input = $json;
const receipt = input.receipt || {};
const profile = input.customer_profile || {};
const status = receipt.status;

if (!receipt.receipt_id || !receipt.customer_id) {
  throw new Error('M02 input invalid — missing receipt.receipt_id / customer_id');
}
if (!['extracted', 'categorized'].includes(status)) {
  throw new Error('M02 input invalid — unsupported status: ' + status);
}
if (!profile.integrations || !profile.integrations.archive) {
  throw new Error('M02 input invalid — profile.integrations.archive missing');
}

const crypto = require('crypto');
const secret = $env.PP_HMAC_SECRET || '';
const nowSec = Math.floor(Date.now() / 1000).toString();
const traceId = input.trace_id || ('trc_' + Math.random().toString(36).slice(2, 12));
const idempotencyKey = input.idempotency_key || ('ik_M02_' + receipt.receipt_id);

const archiveBody = JSON.stringify({ customer_profile: profile, trace_id: traceId });
function sha256Hex(s) { return crypto.createHash('sha256').update(s, 'utf-8').digest('hex'); }
function sign(method, path, ts, bodyStr) {
  const canonical = [method.toUpperCase(), path, ts, sha256Hex(bodyStr)].join('\n');
  return crypto.createHmac('sha256', secret).update(canonical).digest('hex');
}
const archivePath = '/api/v1/receipts/' + receipt.receipt_id + '/archive';

return [{
  json: {
    receipt,
    customer_profile: profile,
    trace_id:        traceId,
    idempotency_key: idempotencyKey,
    __hmacTs:        nowSec,
    __archiveBody:   archiveBody,
    __archivePath:   archivePath,
    __archiveSig:    sign('POST', archivePath, nowSec, archiveBody)
  }
}];
